mapper.select:
SELECT * FROM exam_room
WHERE roomCapacity >= #{capacity}
AND availableSeats >= #{capacity}
AND status = '0'
AND roomId NOT IN (
    SELECT DISTINCT roomId
    FROM exam_arrange
    WHERE arrangeDate = #{date}
    AND session = #{session}
    AND status IN ('1', '2')
)
ORDER BY roomName

mapper.update:
UPDATE exam_room
SET availableSeats = availableSeats + #{change}
WHERE roomId = #{roomId}

mapper.select:
SELECT COUNT(*)
FROM exam_arrange
WHERE roomId = #{roomId}
AND arrangeDate = #{date}
AND session = #{session}
AND status IN ('1', '2')
